"use server";

import { revalidateTag } from 'next/cache';

type CreatePostInput = {
  title: string;
  content: string;
};

export type CreatePostState = {
  success: boolean;
  message: string;
};

export async function createPost(
  _prevState: CreatePostState,
  formData: FormData
): Promise<CreatePostState> {
  const title = String(formData.get('title') ?? '').trim();
  const content = String(formData.get('content') ?? '').trim();

  if (!title || !content) {
    return {
      success: false,
      message: 'Title and content are required.'
    };
  }

  const post: CreatePostInput = { title, content };

  await savePost(post);

  // Ensure the next request does not serve stale cached content.
  revalidateTag('posts', 'max');

  return {
    success: true,
    message: 'Post created successfully.'
  };
}

async function savePost(post: CreatePostInput) {
  void post;
  // Replace with your persistence layer.
}

import { createPost, type CreatePostState } from './actions';

const initialState: CreatePostState = {
  success: false,
  message: ''
};

export default function Home() {
  return (
    <main>
      <h1>Posts</h1>
      <form action={createPost}>
        <div>
          <label htmlFor="title">Title</label>
          <input id="title" name="title" type="text" />
        </div>
        <div>
          <label htmlFor="content">Content</label>
          <textarea id="content" name="content" />
        </div>
        <button type="submit">Create post</button>
      </form>
      <p>
        After submitting, the posts cache tag is revalidated using
        <code>revalidateTag(&apos;posts&apos;, &apos;max&apos;)</code> to avoid stale
        content on the next page load.
      </p>
    </main>
  );
}

